source_table_name = #{sourceTableName}, source_column_names_json = #{sourceColumnNamesJson}, source_column_signature = #{sourceColumnSignature}, target_table_name = #{targetTableName}, target_column_names_json = #{targetColumnNamesJson}, target_column_signature = #{targetColumnSignature}, relation_type = #{relationType}, description = #{description}, is_enabled = #{isEnabled}, update_time = #{updateTime},
